class Solution {
public:
    Solution(int m, int n) : total(m * n), m(m), n(n), count(0) {}

    vector<int> flip() {
        int randIndex = rand() % (total - count);
        count++;
        if (map.find(randIndex) != map.end()) {
            randIndex = map[randIndex];
        }
        int lastIndex = total - count;
        if (map.find(lastIndex) != map.end()) {
            map[randIndex] = map[lastIndex];
        } else {
            map[randIndex] = lastIndex;
        }
        return {randIndex / n, randIndex % n};
    }

    void reset() {
        count = 0;
        map.clear();
    }

private:
    unordered_map<int, int> map;
    int total;
    int m;
    int n;
    int count;
};

